queries.sparql:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
SELECT ?iid ?pi ((SUM(?rev)/SUM(?emp)) AS ?rpe) WHERE {
  ?x a :Industries ; p:IndustryID ?iid ; p:Primary_Industry ?pi ; p:AnnualRevenue ?rev ; p:NumberOfEmployees ?emp .
} GROUP BY ?iid ?pi

