  full: { SELECT ?pi ?mcj ?rev ((?rev*100.0)/?total AS ?pct) WHERE { { SELECT ?pi ?mcj (SUM(xsd:double(?r)) AS ?rev) WHERE { ?x a :Industries ; p:Primary_Industry ?pi ; p:Most_Common_Job ?mcj ; p:AnnualRevenue ?r } GROUP BY ?pi ?mcj } { SELECT (SUM(xsd:double(?r2)) AS ?total) WHERE { ?y a :Industries ; p:AnnualRevenue ?r2 } } } }
